38: // newPlugin allocates and returns a new gRPC (external) backendplugin.Plugin.
39: func newPlugin(descriptor PluginDescriptor) backendplugin.PluginFactoryFunc {
40: 	return func(pluginID string, logger log.Logger, tracer trace.Tracer, env func() []string) (backendplugin.Plugin, error) {
41: 		return newGrpcPlugin(descriptor, logger, tracer, env)
