45: func newGrpcPlugin(descriptor PluginDescriptor, logger log.Logger, tracer trace.Tracer, env func() []string) (*grpcPlugin, error) {
46: 	return &grpcPlugin{
47: 		descriptor: descriptor,
48: 		logger:     logger,
49: 		clientFactory: func() (*plugin.Client, error) {
50: 			clientConfig, err := newClientConfig(descriptor, env(), logger, tracer)
51: 			if err != nil {
52: 				return nil, err
53: 			}
54: 			return plugin.NewClient(clientConfig), nil
55: 		},
56: 		state: pluginStateNotStarted,
57: 	}, nil
58: }
