68: func (p *grpcPlugin) Start(_ context.Context) error {
69: 	p.mutex.Lock()
70: 	defer p.mutex.Unlock()
71: 
72: 	p.state = pluginStateStartInit
73: 
74: 	var err error
75: 	p.client, err = p.clientFactory()
76: 	if err != nil {
77: 		p.state = pluginStateStartFail
78: 		return err
79: 	}
80: 	rpcClient, err := p.client.Client()
81: 	if err != nil {
82: 		p.state = pluginStateStartFail
83: 		return err
84: 	}
85: 
86: 	if p.client.NegotiatedVersion() < 2 {
87: 		p.state = pluginStateStartFail
88: 		return errors.New("plugin protocol version not supported")
89: 	}
90: 	p.pluginClient, err = newClientV2(p.descriptor, p.logger, rpcClient)
91: 	if err != nil {
92: 		p.state = pluginStateStartFail
93: 		return err
94: 	}
95: 
96: 	if p.pluginClient == nil {
97: 		p.state = pluginStateStartFail
98: 		return errors.New("no compatible plugin implementation found")
99: 	}
100: 
101: 	p.state = pluginStateStartSuccess
102: 	return nil
103: }
