105: func (p *grpcPlugin) Stop(_ context.Context) error {
106: 	p.mutex.Lock()
107: 	defer p.mutex.Unlock()
108: 
109: 	if p.client != nil {
110: 		p.client.Kill()
111: 	}
112: 	p.state = pluginStateStopped
113: 	return nil
114: }
