399: 		if errorSourceErr != nil {
400: 			logger.Error("Could not set plugin error source", "error", errorSourceErr)
401: 		}
402: 		// plugin request has failed after being sent from the Grafana server
403: 		return plugins.ErrPluginRequestFailureErrorBase.Errorf("%v", err)
404: 	}
405: 	return fmt.Errorf("%v: %w", "Failed to query data", err)
