45: func (b *BackendClientInit) Initialize(ctx context.Context, p *plugins.Plugin) (*plugins.Plugin, error) {
46: 	if p.Backend {
47: 		backendFactory := b.backendProvider.BackendFactory(ctx, p)
48: 		if backendFactory == nil {
49: 			return nil, errors.New("could not find backend factory for plugin")
50: 		}
51: 
52: 		// this will ensure that the env variables are calculated every time a plugin is started
53: 		envFunc := func() []string { return b.envVarProvider.PluginEnvVars(ctx, p) }
54: 
55: 		if backendClient, err := backendFactory(p.ID, p.Logger(), b.tracer, envFunc); err != nil {
56: 			return nil, err
57: 		} else {
58: 			p.RegisterClient(backendClient)
59: 		}
60: 	}
61: 	return p, nil
